sys_ui_policy.script_false:
function onCondition() {
	// this field needs to be on the form to get the value, but it doesn't need to be shown.
	g_form.setDisplay('tasking_authority.u_external_flag',false);

	// STRY0074599 this fires after the other story, by not having u_external_ou in here, we are taking what the other UI policy set for it.

	// STRY0071489 - If new setting for system property definie if Primary Office Must Match Internal Tasking Authority
	if(g_scratchpad.primary_office_must_match_Internal_tasking_authority == 'true'){
		// STRY0093905 
		if(g_form.getValue('tasking_authority') != g_form.getValue('primary_office')){
			g_form.clearValue('primary_office');
			var taskingAuthority = g_form.getValue('tasking_authority');
			g_form.setValue('primary_office',taskingAuthority);
		}		
	}

}

sys_ui_policy.script_true:
function onCondition() {
	// this field needs to be on the form to get the value, but it doesn't need to be shown.
	g_form.setDisplay('tasking_authority.u_external_flag',false);

	// STRY0074599 this fires after the other story.
	// so, if Tasking Authority and on Parent, this hould hide the External OU field on the task
	g_form.setDisplay('u_external_ou',false);

}
